+    fn test_write_file_permissions_unix() {
+        use std::os::unix::fs::PermissionsExt;
+        asupersync::test_utils::run_test(|| async {
+            let tmp = tempfile::tempdir().unwrap();
+            let tool = WriteTool::new(tmp.path());
